#import "AlarmManager.h"


@implementation AlarmManager

+ (instancetype)sharedManager {
    static AlarmManager *instance;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        instance = [[AlarmManager alloc] init];
    });
    return instance;
}

#pragma mark - Schedule All

+ (void)scheduleAllAlarms {
    [[UNUserNotificationCenter currentNotificationCenter] removeAllPendingNotificationRequests];

    for (AlarmModel *alarm in [AlarmModel enabledAlarms]) {
        [self scheduleAlarm:alarm];
    }
}

#pragma mark - Schedule Single Alarm

+ (void)scheduleAlarm:(AlarmModel *)alarm {
    if (!alarm.isEnabled.boolValue) return;

    // 每次先清理旧的
    [self cancelAlarm:alarm];

    // 1) 如果没有设置周期 weekday，按一次性闹钟处理
    if (alarm.selectedDayIndexes.count == 0) {
        [self scheduleOneTimeAlarm:alarm];
    }
    // 2) 周期闹钟（每周重复）
    else {
        for (NSNumber *weekday in alarm.selectedDayIndexes) {
            [self scheduleRepeatingAlarm:alarm weekday:weekday.integerValue];
        }
    }
}

#pragma mark - One-time alarm

+ (void)scheduleOneTimeAlarm:(AlarmModel *)alarm {
    NSDateComponents *cmp =
        [[NSCalendar currentCalendar] components:(NSCalendarUnitYear |
                                                  NSCalendarUnitMonth |
                                                  NSCalendarUnitDay |
                                                  NSCalendarUnitHour |
                                                  NSCalendarUnitMinute)
                                        fromDate:alarm.selectedTime];

    NSString *idBase = [NSString stringWithFormat:@"alarm_%ld", alarm.alarmId];

    [self registerNotification:cmp alarm:alarm identifier:idBase];

    // Interval 重复
    for (NSInteger i = 1; i < alarm.repeatTimes; i++) {
        NSDate *next = [alarm.selectedTime dateByAddingTimeInterval:i * alarm.intervalMinutes * 60];
        NSDateComponents *c2 =
            [[NSCalendar currentCalendar] components:(NSCalendarUnitYear |
                                                      NSCalendarUnitMonth |
                                                      NSCalendarUnitDay |
                                                      NSCalendarUnitHour |
                                                      NSCalendarUnitMinute)
                                            fromDate:next];
        NSString *iid = [NSString stringWithFormat:@"%@_r%ld", idBase, (long)i];
        [self registerNotification:c2 alarm:alarm identifier:iid];
    }
}

#pragma mark - Repeating weekly

+ (void)scheduleRepeatingAlarm:(AlarmModel *)alarm weekday:(NSInteger)weekday {
    NSDateComponents *cmp = [[NSDateComponents alloc] init];
    cmp.weekday = weekday;  // 1-7
    cmp.hour = alarm.selectedTime.hour;
    cmp.minute = alarm.selectedTime.minute;

    NSString *idBase = [NSString stringWithFormat:@"alarm_%ld_%ld",
                        alarm.alarmId, (long)weekday];

    [self registerNotification:cmp alarm:alarm identifier:idBase repeating:YES];

    // interval repeat
    for (NSInteger i = 1; i < alarm.repeatTimes; i++) {
        NSDate *next = [alarm.selectedTime dateByAddingTimeInterval:i * alarm.intervalMinutes * 60];
        NSDateComponents *c2 = [[NSDateComponents alloc] init];
        c2.weekday = weekday;
        c2.hour = next.hour;
        c2.minute = next.minute;

        NSString *iid = [NSString stringWithFormat:@"%@_r%ld", idBase, (long)i];
        [self registerNotification:c2 alarm:alarm identifier:iid repeating:YES];
    }
}

#pragma mark - Register notification

- (void)requestNotificationAuthorization {
    UNUserNotificationCenter *center = [UNUserNotificationCenter currentNotificationCenter];

    // 设置通知选项
    UNAuthorizationOptions options = UNAuthorizationOptionAlert |
                                     UNAuthorizationOptionSound |
                                     UNAuthorizationOptionBadge;

    [center requestAuthorizationWithOptions:options
                          completionHandler:^(BOOL granted, NSError * _Nullable error) {
        if (granted) {
            NSLog(@"通知权限已授权");

            // 获取当前设置
            [center getNotificationSettingsWithCompletionHandler:^(UNNotificationSettings * _Nonnull settings) {
                NSLog(@"通知设置: %@", settings);

                // 如果授权了，注册远程通知
                if (settings.authorizationStatus == UNAuthorizationStatusAuthorized) {
                    dispatch_async(dispatch_get_main_queue(), ^{
                        [[UIApplication sharedApplication] registerForRemoteNotifications];
                    });
                }
            }];
        } else {
            NSLog(@"通知权限被拒绝");
        }

        if (error) {
            NSLog(@"请求通知权限出错: %@", error.localizedDescription);
        }
    }];
}

+ (void)registerNotification:(NSDateComponents *)comp
                       alarm:(AlarmModel *)alarm
                   identifier:(NSString *)identifier {

    [self registerNotification:comp alarm:alarm identifier:identifier repeating:NO];

}

+ (void)registerNotification:(NSDateComponents *)comp
                       alarm:(AlarmModel *)alarm
                   identifier:(NSString *)identifier
                    repeating:(BOOL)repeating {

    UNMutableNotificationContent *content = [[UNMutableNotificationContent alloc] init];
    content.title = alarm.name ?: @"Alarm";
    content.body = @"Alarm clock";
    content.sound = [UNNotificationSound soundNamed:alarm.ringtoneName];

    content.userInfo = @{
        @"ringtoneName": [NSString stringWithFormat:@"%@", alarm.ringtoneName],
    };

    UNCalendarNotificationTrigger *trigger =
        [UNCalendarNotificationTrigger triggerWithDateMatchingComponents:comp
                                                                 repeats:repeating];

    UNNotificationRequest *request =
        [UNNotificationRequest requestWithIdentifier:identifier
                                             content:content
                                             trigger:trigger];

    [[UNUserNotificationCenter currentNotificationCenter]
     addNotificationRequest:request withCompletionHandler:nil];

}

#pragma mark - Cancel Alarm

+ (void)cancelAlarm:(AlarmModel *)alarm {
    NSMutableArray *ids = [NSMutableArray array];

    NSString *base = [NSString stringWithFormat:@"alarm_%ld", alarm.alarmId];

    // 一次性闹钟
    [ids addObject:base];

    for (NSInteger i = 1; i < alarm.repeatTimes; i++) {
        [ids addObject:[NSString stringWithFormat:@"%@_r%ld", base, (long)i]];
    }

    // 如果有 weekday 则加
    for (NSNumber *weekday in alarm.selectedDayIndexes) {
        NSString *weekBase = [NSString stringWithFormat:@"%@_%ld", base, weekday.integerValue];
        [ids addObject:weekBase];
        for (NSInteger i = 1; i < alarm.repeatTimes; i++) {
            [ids addObject:[NSString stringWithFormat:@"%@_r%ld", weekBase, (long)i]];
        }
    }

    [[UNUserNotificationCenter currentNotificationCenter]
     removePendingNotificationRequestsWithIdentifiers:ids];
}

- (void)playAlarmSoundForNotification:(UNNotification *)notification {
    NSString *ringtoneName = notification.request.content.userInfo[@"ringtoneName"];

    if ([ringtoneName isEqual:@"默认铃声"]) {
        ringtoneName = @"Default ringtone";
    } else if ([ringtoneName isEqual:@"经典"]) {
        ringtoneName = @"Classic ringtone";
    } else if ([ringtoneName isEqual:@"天气"]) {
        ringtoneName = @"Weather ringtone";
    } else if ([ringtoneName isEqual:@"自然"]) {
        ringtoneName = @"Natural ringtone";
    }

    if (!ringtoneName) ringtoneName = @"default";

    NSURL *url = [[NSBundle mainBundle] URLForResource:ringtoneName withExtension:@"mp3"];

    AVAudioSession *session = [AVAudioSession sharedInstance];
    [session setCategory:AVAudioSessionCategoryPlayback error:nil];
    [session setActive:YES error:nil];


    self.player = [[AVAudioPlayer alloc] initWithContentsOfURL:url error:nil];
    self.player.numberOfLoops = -1; // 无限循环
    [self.player play];
    [[NSNotificationCenter defaultCenter] postNotificationName:@"popAlert" object:nil];
}

- (void)stopAlarmSound {
    [self.player stop];
    self.player = nil;
}

@end

