    ClockCell *cell = [collectionView dequeueReusableCellWithReuseIdentifier:@"ClockCell" forIndexPath:indexPath];

    AlarmModel *alarm = self.alarms[indexPath.item];
    BOOL isSelected = [self.selectedIndexPaths containsObject:indexPath];

