- (void) saveAlarm:(UIButton *)sender {
    NSDate *selectedTime = self.selectedTime;
    NSString *name = self.settingView.nameTextField.text;
    NSString *ringtonename = self.settingView.ringtoneValueLabel.text;
    NSString *reminderminutes = self.settingView.reminderValueLabel.text;
    NSNumber *isenable = @1;
    self.Alarm.selectedTime = selectedTime;
    self.Alarm.name = name;
    self.Alarm.ringtoneName = ringtonename;
    self.Alarm.reminderMinutes = reminderminutes;
    self.Alarm.isEnabled = isenable;

    if (self.isCustomize) {
        NSMutableSet *indexes = self.repeatView.selectedDayIndexes;
        NSNumber *isholiday = @(self.repeatView.holidaySwitch.on);
        self.Alarm.selectedDayIndexes = indexes;
        self.Alarm.holidaySkipEnabled = isholiday;
    }

    if (self.isNewAlarm) {
        [AlarmModel addAlarm:self.Alarm];
    } else {
        [AlarmModel updateAlarm:self.Alarm];
    }
    [[NSNotificationCenter defaultCenter] postNotificationName:@"AlarmDataUpdated" object:nil];
    [self dismissViewControllerAnimated:YES completion:nil];
}

