 @implementation ClockEditViewController
+
++ (NSString *)englishRingtoneName:(NSString *)ringtoneName {
+    NSDictionary<NSString *, NSString *> *ringtoneMap = @{
+        @"默认铃声": @"Default",
+        @"经典": @"Classic",
+        @"天气": @"Weather",
+        @"自然": @"Nature",
+    };
+
+    NSString *mappedName = ringtoneMap[ringtoneName];
+    return mappedName.length > 0 ? mappedName : ringtoneName;
+}
+
++ (NSString *)englishReminderText:(NSString *)reminderText {
+    if (reminderText.length == 0 || [reminderText isEqualToString:@"Close"]) {
+        return reminderText;
+    }
+
+    if ([reminderText rangeOfString:@"分钟"].location == NSNotFound &&
+        [reminderText rangeOfString:@"次"].location == NSNotFound) {
+        return reminderText;
+    }
+
+    NSRegularExpression *regex = [NSRegularExpression regularExpressionWithPattern:@"(\\d+)" options:0 error:nil];
+    NSArray<NSTextCheckingResult *> *matches = [regex matchesInString:reminderText options:0 range:NSMakeRange(0, reminderText.length)];
+    if (matches.count >= 2) {
+        NSString *interval = [reminderText substringWithRange:[matches[0] rangeAtIndex:1]];
+        NSString *times = [reminderText substringWithRange:[matches[1] rangeAtIndex:1]];
+        return [NSString stringWithFormat:@"Interval of %@ min, %@ times", interval, times];
+    }
+
+    return reminderText;
+}

